import websocket
import json
from secrets import token_hex

# Set up a WebSocket server on port 8000
ws = websocket.WebSocketApp("ws://localhost:8000")

# Define a function to handle incoming messages
def handle_message(ws, message):
    # Parse the JSON message and extract the "action" field
    data = json.loads(message)
    action = data["action"]
    
    # Handle the "turn_on" action
    if action == "turn_on":
        print("Turning on the device...")
    else:
        print("Invalid action received.")

# Define a function to handle incoming connections
def handle_connect(ws):
    # Send a welcome message to the client
    ws.send("Welcome to the IoT device real-time control interface!")
    
    # Start listening for messages from the client
    ws.run_forever(handle_message)

# Set up the WebSocket server with the handle_connect function
ws.run_server(handle_connect, host="localhost", port=8000)